  1→import type { Candidate, SearchFilters } from "@rearden/types";
  2→
  3→export interface ScoredCandidate {
  4→  candidate: Candidate;
  5→  score: number;
  6→  matchReason: string;
  7→}
  8→
  9→export function searchCandidates(
 10→  candidates: Candidate[],
 11→  query: string,
 12→  filters?: SearchFilters
 13→): ScoredCandidate[] {
 14→  // Handle empty query - return all candidates with random scores
 15→  if (!query.trim()) {
 16→    return candidates
 17→      .filter((candidate) => applyFilters(candidate, filters))
 18→      .map((candidate) => ({
 19→        candidate,
 20→        score: Math.floor(Math.random() * 16) + 85, // 85-100
 21→        matchReason: "Featured Talent",
 22→      }))
 23→      .sort((a, b) => b.score - a.score);
 24→  }
 25→
 26→  // Parse query into lowercase tokens
 27→  const tokens = query.toLowerCase().trim().split(/\s+/);
 28→
 29→  // Score each candidate
 30→  const scoredCandidates = candidates
 31→    .map((candidate): ScoredCandidate => {
 32→      let totalScore = 0;
 33→      const matchReasons: string[] = [];
 34→      const matchedSkills: string[] = [];
 35→
 36→      // Skill matching
 37→      for (const skill of candidate.skills) {
 38→        const skillLower = skill.toLowerCase();
 39→
 40→        // Exact match
 41→        if (tokens.some((token) => token === skillLower)) {
 42→          totalScore += 25;
 43→          matchedSkills.push(skill);
 44→        }
 45→        // Partial match
 46→        else if (tokens.some((token) => skillLower.includes(token))) {
 47→          totalScore += 15;
 48→          matchedSkills.push(skill);
 49→        }
 50→      }
 51→
 52→      if (matchedSkills.length > 0) {
 53→        matchReasons.push(`Skills: ${matchedSkills.join(", ")}`);
 54→      }
 55→
 56→      // Title matching
 57→      const titleLower = candidate.title.toLowerCase();
 58→      const titleMatches = tokens.filter((token) => titleLower.includes(token));
 59→      if (titleMatches.length > 0) {
 60→        totalScore += titleMatches.length * 20;
 61→        matchReasons.push(`Title: ${candidate.title}`);
 62→      }
 63→
 64→      // Location matching
 65→      const locationLower = candidate.location.toLowerCase();
 66→      const locationMatches = tokens.filter((token) => locationLower.includes(token));
 67→      if (locationMatches.length > 0) {
 68→        totalScore += locationMatches.length * 15;
 69→        matchReasons.push(`Location: ${candidate.location}`);
 70→      }
 71→
 72→      // Bio matching
 73→      const bioLower = candidate.bio.toLowerCase();
 74→      const bioMatches = tokens.filter((token) => bioLower.includes(token));
 75→      if (bioMatches.length > 0) {
 76→        totalScore += bioMatches.length * 5;
 77→      }
 78→
 79→      // Experience keywords
 80→      const queryLower = query.toLowerCase();
 81→      if (queryLower.includes("senior") && candidate.experience >= 5) {
 82→        totalScore += 10;
 83→      }
 84→      if (queryLower.includes("junior") && candidate.experience <= 3) {
 85→        totalScore += 10;
 86→      }
 87→      if (queryLower.includes("lead") && candidate.experience >= 8) {
 88→        totalScore += 10;
 89→      }
 90→
 91→      // Calculate max possible score for normalization
 92→      const maxSkillScore = tokens.length * 25;
 93→      const maxTitleScore = tokens.length * 20;
 94→      const maxLocationScore = tokens.length * 15;
 95→      const maxBioScore = tokens.length * 5;
 96→      const maxExperienceBonus = 10;
 97→      const maxPossibleScore =
 98→        maxSkillScore + maxTitleScore + maxLocationScore + maxBioScore + maxExperienceBonus;
 99→
100→      // Normalize to 0-100
101→      const normalizedScore = maxPossibleScore > 0
102→        ? Math.min(100, Math.round((totalScore / maxPossibleScore) * 100))
103→        : 0;
104→
105→      const matchReason = matchReasons.length > 0
106→        ? matchReasons.join(" | ")
107→        : "General match";
108→
109→      return {
110→        candidate,
111→        score: normalizedScore,
112→        matchReason,
113→      };
114→    })
115→    .filter((scored) => scored.score > 0) // Filter out zero scores
116→    .filter((scored) => applyFilters(scored.candidate, filters)) // Apply additional filters
117→    .sort((a, b) => b.score - a.score); // Sort by score descending
118→
119→  return scoredCandidates;
120→}
121→
122→function applyFilters(candidate: Candidate, filters?: SearchFilters): boolean {
123→  if (!filters) return true;
124→
125→  // Skills filter
126→  if (filters.skills && filters.skills.length > 0) {
127→    const candidateSkillsLower = candidate.skills.map((s) => s.toLowerCase());
128→    const hasAllSkills = filters.skills.every((skill) =>
129→      candidateSkillsLower.some((cs) => cs.includes(skill.toLowerCase()))
130→    );
131→    if (!hasAllSkills) return false;
132→  }
133→
134→  // Location filter
135→  if (filters.location) {
136→    const locationMatch = candidate.location
137→      .toLowerCase()
138→      .includes(filters.location.toLowerCase());
139→    if (!locationMatch) return false;
140→  }
141→
142→  // Experience range filter
143→  if (filters.experienceMin !== undefined && candidate.experience < filters.experienceMin) {
144→    return false;
145→  }
146→  if (filters.experienceMax !== undefined && candidate.experience > filters.experienceMax) {
147→    return false;
148→  }
149→
150→  // Availability filter
151→  if (filters.availability && filters.availability.length > 0) {
152→    if (!filters.availability.includes(candidate.availability)) {
153→      return false;
154→    }
155→  }
156→
157→  return true;
158→}
